import {useState} from 'react';


const circuits = [
    {name : 'Austrailia', imageUrl:'data:image/png;base64,'},
    {name : 'China', imageUrl:'data:image/png;base64,'},
    {name : 'Suzuka', imageUrl:'data:image/png;base64,'},
    {name : 'Miami', imageUrl:'data:image/png;base64,'},
    {name : 'Canada', imageUrl:'data:image/png;base64,'},
    {name : 'Monaco', imageUrl: 'data:image/png;base64,'},
    {name : 'Barcelona-Catalunya', imageUrl:'data:image/png;base64,'},
    {name : 'Austria', imageUrl:'data:image/png;base64,'},
    {name : 'SilverStone', imageUrl:'data:image/png;base64,'},
    {name : 'Belgium', imageUrl:'data:image/png;base64,'},
    {name : 'Hungary', imageUrl:'data:image/png;base64,'},
    {name : 'Netherlands', imageUrl : 'data:image/png;base64,'},
    {name : 'Italy', imageUrl:'data:image/png;base64,'},
    {name : 'Spain', imageUrl:'data:image/png;base64,'},
    {name : 'Azerbaijan', imageUrl:'data:image/png;base64,'},
    {name :'Singapore', imageUrl:'data:image/png;base64,'},
    {name :'United States', imageUrl:'data:image/png;base64,'},
    {name :'Mexico', imageUrl:'data:image/png;base64,'},
    {name :'Brazil', imageUrl:'data:image/png;base64,'},
    {name :'Las Vegas', imageUrl:'data:image/png;base64,'},
    {name :'Qatar', imageUrl:'data:image/png;base64,'},
    {name :'Abu Dhabi', imageUrl:'data:image/png;base64,'},
];

function CircuitSlider(){
    const [index, setIndex] = useState(0);
    
    const handlePrev = () => {
        setIndex((prevIndex) => (prevIndex === 0 ? circuits.length - 1 : prevIndex - 1));
    };

    const handleNext = () => {
        setIndex ((prevIndex) => (prevIndex === circuits.length - 1 ? 0 : prevIndex + 1));
    };

    const currentCircuit = circuits[index];

    return(
        <div className="circuit-slider">
            

            <div className="circuit-displayt">
                <img src={currentCircuit.imageUrl} alt={currentCircuit.name} width="400"/>
                <h3>{currentCircuit.name}</h3>
            </div>

            <button onClick={handlePrev}>◀Prev</button>
            <button onClick={handleNext}>Next ▶</button>
        </div>
    );
}

export default CircuitSlider;